export type Instrument = 'Kick' | 'Snare' | 'HiHat' | 'OpenHH' | 'Clap' | 'Cowbell';

export interface Track {
  id: Instrument;
  name: string;
  color: string;
  steps: boolean[]; // 64 steps for 4 bars (16 steps per bar)
}

export interface SequencerState {
  bpm: number;
  isPlaying: boolean;
  currentStep: number;
  tracks: Track[];
}

export interface AIPatternResponse {
  patterns: {
    [key in Instrument]?: number[]; // Array of indices (0-63) where notes are played
  };
  genre: string;
}

import { Instrument, Track } from './types';

export const TOTAL_STEPS = 64;
export const STEPS_PER_BAR = 16;
export const DEFAULT_BPM = 120;

export const INITIAL_TRACKS: Track[] = [
  { id: 'Kick', name: 'Kick', color: 'bg-rose-500', steps: Array(TOTAL_STEPS).fill(false) },
  { id: 'Snare', name: 'Snare', color: 'bg-indigo-500', steps: Array(TOTAL_STEPS).fill(false) },
  { id: 'HiHat', name: 'Hi-Hat', color: 'bg-emerald-400', steps: Array(TOTAL_STEPS).fill(false) },
  { id: 'OpenHH', name: 'Open HH', color: 'bg-yellow-400', steps: Array(TOTAL_STEPS).fill(false) },
  { id: 'Clap', name: 'Clap', color: 'bg-orange-400', steps: Array(TOTAL_STEPS).fill(false) },
  { id: 'Cowbell', name: 'Cowbell', color: 'bg-fuchsia-400', steps: Array(TOTAL_STEPS).fill(false) },
];

export const INSTRUMENT_MIDI_MAP: Record<Instrument, number> = {
  Kick: 36,
  Snare: 38,
  HiHat: 42,
  OpenHH: 46,
  Clap: 39,
  Cowbell: 56,
};

import { Instrument } from '../types';

class AudioEngine {
  private ctx: AudioContext | null = null;

  init() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (this.ctx.state === 'suspended') {
      this.ctx.resume();
    }
  }

  playInstrument(inst: Instrument) {
    if (!this.ctx) this.init();
    if (!this.ctx) return;

    const time = this.ctx.currentTime;

    switch (inst) {
      case 'Kick':
        this.playKick(time);
        break;
      case 'Snare':
        this.playSnare(time);
        break;
      case 'HiHat':
        this.playHiHat(time, 0.05);
        break;
      case 'OpenHH':
        this.playHiHat(time, 0.2);
        break;
      case 'Clap':
        this.playClap(time);
        break;
      case 'Cowbell':
        this.playCowbell(time);
        break;
    }
  }

  private playKick(time: number) {
    const osc = this.ctx!.createOscillator();
    const gain = this.ctx!.createGain();
    osc.connect(gain);
    gain.connect(this.ctx!.destination);

    osc.frequency.setValueAtTime(150, time);
    osc.frequency.exponentialRampToValueAtTime(0.01, time + 0.5);
    gain.gain.setValueAtTime(1, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.5);

    osc.start(time);
    osc.stop(time + 0.5);
  }

  private playSnare(time: number) {
    const noise = this.ctx!.createBufferSource();
    const noiseBuffer = this.ctx!.createBuffer(1, this.ctx!.sampleRate * 0.1, this.ctx!.sampleRate);
    const data = noiseBuffer.getChannelData(0);
    for (let i = 0; i < data.length; i++) data[i] = Math.random() * 2 - 1;
    noise.buffer = noiseBuffer;

    const noiseFilter = this.ctx!.createBiquadFilter();
    noiseFilter.type = 'highpass';
    noiseFilter.frequency.value = 1000;
    noise.connect(noiseFilter);

    const noiseGain = this.ctx!.createGain();
    noiseGain.gain.setValueAtTime(1, time);
    noiseGain.gain.exponentialRampToValueAtTime(0.01, time + 0.1);
    noiseFilter.connect(noiseGain);
    noiseGain.connect(this.ctx!.destination);

    const osc = this.ctx!.createOscillator();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(100, time);
    const oscGain = this.ctx!.createGain();
    oscGain.gain.setValueAtTime(0.7, time);
    oscGain.gain.exponentialRampToValueAtTime(0.01, time + 0.1);
    osc.connect(oscGain);
    oscGain.connect(this.ctx!.destination);

    noise.start(time);
    osc.start(time);
    noise.stop(time + 0.2);
    osc.stop(time + 0.2);
  }

  private playHiHat(time: number, duration: number) {
    const noise = this.ctx!.createBufferSource();
    const buffer = this.ctx!.createBuffer(1, this.ctx!.sampleRate * duration, this.ctx!.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < data.length; i++) data[i] = Math.random() * 2 - 1;
    noise.buffer = buffer;

    const filter = this.ctx!.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 7000;
    noise.connect(filter);

    const gain = this.ctx!.createGain();
    gain.gain.setValueAtTime(0.3, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + duration);
    filter.connect(gain);
    gain.connect(this.ctx!.destination);

    noise.start(time);
    noise.stop(time + duration);
  }

  private playClap(time: number) {
    const noise = this.ctx!.createBufferSource();
    const bufferSize = this.ctx!.sampleRate * 0.1;
    const buffer = this.ctx!.createBuffer(1, bufferSize, this.ctx!.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < data.length; i++) data[i] = Math.random() * 2 - 1;
    noise.buffer = buffer;

    const filter = this.ctx!.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 1500;
    noise.connect(filter);

    const gain = this.ctx!.createGain();
    // Claps often have 3-4 bursts
    for (let i = 0; i < 4; i++) {
      gain.gain.setValueAtTime(0.8, time + i * 0.01);
      gain.gain.exponentialRampToValueAtTime(0.01, time + i * 0.01 + 0.01);
    }
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.1);

    filter.connect(gain);
    gain.connect(this.ctx!.destination);

    noise.start(time);
    noise.stop(time + 0.2);
  }

  private playCowbell(time: number) {
    const osc1 = this.ctx!.createOscillator();
    const osc2 = this.ctx!.createOscillator();
    osc1.type = 'square';
    osc2.type = 'square';
    osc1.frequency.value = 540;
    osc2.frequency.value = 800;

    const gain = this.ctx!.createGain();
    gain.gain.setValueAtTime(0.5, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.3);

    const filter = this.ctx!.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = 800;

    osc1.connect(filter);
    osc2.connect(filter);
    filter.connect(gain);
    gain.connect(this.ctx!.destination);

    osc1.start(time);
    osc2.start(time);
    osc1.stop(time + 0.3);
    osc2.stop(time + 0.3);
  }
}

export const audioEngine = new AudioEngine();

import { GoogleGenAI, Type } from "@google/genai";
import { AIPatternResponse, Instrument } from "../types";

export const generateAIPattern = async (prompt: string): Promise<AIPatternResponse | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Create a professional 4-bar (64 steps) drum pattern for the following style: "${prompt}".
      Return the pattern as a JSON object where keys are the instrument names ('Kick', 'Snare', 'HiHat', 'OpenHH', 'Clap', 'Cowbell') 
      and values are arrays of step indices (0 to 63) where a note should be played. 
      Ensure the pattern is musically coherent and fits the 16th note grid.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            patterns: {
              type: Type.OBJECT,
              properties: {
                Kick: { type: Type.ARRAY, items: { type: Type.INTEGER } },
                Snare: { type: Type.ARRAY, items: { type: Type.INTEGER } },
                HiHat: { type: Type.ARRAY, items: { type: Type.INTEGER } },
                OpenHH: { type: Type.ARRAY, items: { type: Type.INTEGER } },
                Clap: { type: Type.ARRAY, items: { type: Type.INTEGER } },
                Cowbell: { type: Type.ARRAY, items: { type: Type.INTEGER } },
              },
            },
            genre: { type: Type.STRING },
          },
          required: ["patterns", "genre"],
        },
      },
    });

    const data = JSON.parse(response.text.trim());
    return data as AIPatternResponse;
  } catch (error) {
    console.error("Gemini AI failed:", error);
    return null;
  }
};

import { Track, Instrument } from '../types';
import { INSTRUMENT_MIDI_MAP, TOTAL_STEPS } from '../constants';

/**
 * Creates a simple Standard MIDI File (SMF) from the grid.
 * This is a low-level byte array generation for a MIDI Type 0 file.
 */
export const exportToMIDI = (tracks: Track[], bpm: number) => {
  const HEADER_CHUNK_TYPE = [0x4D, 0x54, 0x68, 0x64]; // MThd
  const HEADER_CHUNK_SIZE = [0x00, 0x00, 0x00, 0x06];
  const FORMAT_TYPE = [0x00, 0x00]; // Type 0 (one track)
  const NUMBER_OF_TRACKS = [0x00, 0x01];
  const TIME_DIVISION = [0x00, 0x80]; // 128 ticks per quarter note

  const TRACK_CHUNK_TYPE = [0x4D, 0x54, 0x72, 0x6B]; // MTrk

  // Events
  const events: number[] = [];

  // Set Tempo Meta Event (500,000 microseconds per quarter note = 120bpm)
  const tempo = Math.round(60000000 / bpm);
  events.push(0x00, 0xFF, 0x51, 0x03, (tempo >> 16) & 0xFF, (tempo >> 8) & 0xFF, tempo & 0xFF);

  // Sequence events
  // 16th note = 32 ticks (128 / 4)
  const TICKS_PER_STEP = 32;

  let lastTick = 0;

  for (let step = 0; step < TOTAL_STEPS; step++) {
    const currentTick = step * TICKS_PER_STEP;

    tracks.forEach(track => {
      if (track.steps[step]) {
        const midiNote = INSTRUMENT_MIDI_MAP[track.id];

        // Delta time
        const delta = currentTick - lastTick;
        events.push(...encodeVariableLength(delta));

        // Note On (Channel 10 is 0x99, indexed as 9)
        events.push(0x99, midiNote, 0x64); // Velocity 100
        lastTick = currentTick;

        // Note Off (immediately 20 ticks later or so for drums)
        const offDelta = 20;
        events.push(...encodeVariableLength(offDelta));
        events.push(0x89, midiNote, 0x00);
        lastTick += offDelta;
      }
    });
  }

  // End of Track
  events.push(0x00, 0xFF, 0x2F, 0x00);

  const trackSize = encodeInt32(events.length);
  const midiFile = new Uint8Array([
    ...HEADER_CHUNK_TYPE,
    ...HEADER_CHUNK_SIZE,
    ...FORMAT_TYPE,
    ...NUMBER_OF_TRACKS,
    ...TIME_DIVISION,
    ...TRACK_CHUNK_TYPE,
    ...trackSize,
    ...events
  ]);

  const blob = new Blob([midiFile], { type: 'audio/midi' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'midnight-beat.mid';
  a.click();
  URL.revokeObjectURL(url);
};

function encodeVariableLength(value: number): number[] {
  const result: number[] = [];
  let buffer = value & 0x7F;
  while ((value >>= 7) > 0) {
    buffer <<= 8;
    buffer |= 0x80;
    buffer |= (value & 0x7F);
  }
  while (true) {
    result.push(buffer & 0xFF);
    if (buffer & 0x80) buffer >>= 8;
    else break;
  }
  return result;
}

function encodeInt32(value: number): number[] {
  return [
    (value >> 24) & 0xFF,
    (value >> 16) & 0xFF,
    (value >> 8) & 0xFF,
    value & 0xFF
  ];
}

import React, { useRef } from 'react';
import { Track, Instrument } from '../types';
import { TOTAL_STEPS, STEPS_PER_BAR } from '../constants';

interface SequencerGridProps {
  tracks: Track[];
  currentStep: number;
  onToggleStep: (trackIndex: number, stepIndex: number) => void;
  isPlaying: boolean;
}

const SequencerGrid: React.FC<SequencerGridProps> = ({ tracks, currentStep, onToggleStep, isPlaying }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logic could go here if grid gets too wide

  return (
    <div className="flex flex-col gap-1 w-full overflow-x-auto pb-4 custom-scrollbar" ref={scrollRef}>
      {tracks.map((track, trackIdx) => (
        <div key={track.id} className="flex items-center gap-2 min-w-max">
          <div className="w-24 flex-shrink-0 text-right pr-4 font-semibold text-slate-400 text-sm">
            {track.name}
          </div>
          <div className="flex gap-1">
            {track.steps.map((active, stepIdx) => {
              const isBarStart = stepIdx % STEPS_PER_BAR === 0;
              const isBeatsStart = stepIdx % 4 === 0;
              const isCurrent = isPlaying && currentStep === stepIdx;

              return (
                <button
                  key={stepIdx}
                  onClick={() => onToggleStep(trackIdx, stepIdx)}
                  className={`
                    w-8 h-10 rounded-sm transition-all duration-75
                    ${active ? `${track.color} shadow-lg shadow-${track.color}/20` : 'bg-slate-800 hover:bg-slate-700'}
                    ${isBarStart ? 'border-l-2 border-slate-600' : ''}
                    ${isBeatsStart && !isBarStart ? 'border-l border-slate-700' : ''}
                    ${isCurrent ? 'ring-2 ring-white ring-offset-2 ring-offset-slate-900 z-10' : ''}
                    ${active && isCurrent ? 'brightness-125 scale-105' : ''}
                  `}
                  title={`Step ${stepIdx + 1}`}
                />
              );
            })}
          </div>
        </div>
      ))}
    </div>
  );
};

export default SequencerGrid;

