import React, { useState, useEffect, useCallback, useRef } from 'react';
import { INITIAL_TRACKS, TOTAL_STEPS, DEFAULT_BPM } from './constants';
import { Track, Instrument } from './types';
import SequencerGrid from './components/SequencerGrid';
import Transport from './components/Transport';
import { audioEngine } from './services/audioService';
import { exportToMIDI } from './services/midiService';
import { generateAIPattern } from './services/geminiService';
import { Music, AlertCircle, X, Sparkles, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [tracks, setTracks] = useState<Track[]>(INITIAL_TRACKS);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentStep, setCurrentStep] = useState(0);
  const [bpm, setBpm] = useState(DEFAULT_BPM);
  const [isAIModalOpen, setIsAIModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const timerRef = useRef<number | null>(null);
  const nextStepTimeRef = useRef<number>(0);

  const playStep = useCallback((step: number) => {
    tracks.forEach(track => {
      if (track.steps[step]) {
        audioEngine.playInstrument(track.id);
      }
    });
  }, [tracks]);

  // Scheduler logic
  useEffect(() => {
    if (!isPlaying) {
      if (timerRef.current) clearInterval(timerRef.current);
      return;
    }

    audioEngine.init();

    // Simple interval-based sequencer for web environment
    // 16th note length in ms: (60,000 / BPM) / 4
    const interval = (60000 / bpm) / 4;

    const tick = () => {
      setCurrentStep(prev => {
        const next = (prev + 1) % TOTAL_STEPS;
        playStep(next);
        return next;
      });
    };

    // Play first step immediately if starting
    if (currentStep === 0) playStep(0);

    timerRef.current = window.setInterval(tick, interval);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isPlaying, bpm, playStep]);

  const handleToggleStep = (trackIdx: number, stepIdx: number) => {
    setTracks(prev => {
      const next = [...prev];
      next[trackIdx] = {
        ...next[trackIdx],
        steps: [...next[trackIdx].steps]
      };
      next[trackIdx].steps[stepIdx] = !next[trackIdx].steps[stepIdx];

      // Feedback: play sound on click if not playing
      if (!isPlaying && next[trackIdx].steps[stepIdx]) {
        audioEngine.playInstrument(next[trackIdx].id);
      }

      return next;
    });
  };

  const handleStop = () => {
    setIsPlaying(false);
    setCurrentStep(0);
  };

  const handleBpmChange = (newBpm: number) => {
    setBpm(Math.max(40, Math.min(240, newBpm)));
  };

  const handleGenerateAI = async () => {
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    setError(null);

    try {
      const response = await generateAIPattern(aiPrompt);
      if (response && response.patterns) {
        setTracks(prev => prev.map(track => {
          const newSteps = Array(TOTAL_STEPS).fill(false);
          const patternIndices = response.patterns[track.id];
          if (patternIndices) {
            patternIndices.forEach(idx => {
              if (idx >= 0 && idx < TOTAL_STEPS) {
                newSteps[idx] = true;
              }
            });
          }
          return { ...track, steps: newSteps };
        }));
        setIsAIModalOpen(false);
        setAiPrompt('');
      } else {
        setError("Failed to generate pattern. Please try again.");
      }
    } catch (err) {
      setError("AI generation failed. Check your API key or connection.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col p-4 md:p-8">
      {/* Header */}
      <header className="max-w-7xl mx-auto w-full mb-8 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-indigo-600 rounded-xl flex items-center justify-center shadow-[0_0_20px_rgba(79,70,229,0.5)]">
            <Music className="text-white" size={28} />
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Midnight <span className="text-indigo-500">Beatmaker</span></h1>
            <p className="text-slate-500 text-sm font-medium">4 Bar Studio Engine</p>
          </div>
        </div>

        <div className="hidden md:block px-4 py-2 bg-slate-900 border border-slate-800 rounded-full text-xs font-semibold text-slate-400">
          Pro Sequence Edition • 64 Steps
        </div>
      </header>

      {/* Main Studio Area */}
      <main className="max-w-7xl mx-auto w-full flex flex-col gap-6 flex-grow">
        <div className="relative bg-slate-900/40 border border-slate-800/60 rounded-3xl p-6 shadow-2xl overflow-hidden">
          {/* Subtle Grid Background Pattern */}
          <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#fff 1px, transparent 0)', backgroundSize: '40px 40px' }} />

          <SequencerGrid
            tracks={tracks}
            currentStep={currentStep}
            onToggleStep={handleToggleStep}
            isPlaying={isPlaying}
          />
        </div>

        {/* Floating Controls */}
        <div className="sticky bottom-8 z-40">
          <Transport
            isPlaying={isPlaying}
            onTogglePlay={() => setIsPlaying(!isPlaying)}
            onStop={handleStop}
            bpm={bpm}
            onBpmChange={handleBpmChange}
            onExport={() => exportToMIDI(tracks, bpm)}
            onOpenAI={() => setIsAIModalOpen(true)}
          />
        </div>
      </main>

      {/* AI Modal */}
      {isAIModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl w-full max-w-lg overflow-hidden shadow-2xl">
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
              <div className="flex items-center gap-2">
                <Sparkles className="text-indigo-400" size={20} />
                <h2 className="text-lg font-bold">AI Pattern Generator</h2>
              </div>
              <button onClick={() => setIsAIModalOpen(false)} className="text-slate-500 hover:text-white transition-colors">
                <X size={20} />
              </button>
            </div>

            <div className="p-6 space-y-4">
              <p className="text-sm text-slate-400">
                Describe the vibe you're going for. Our Gemini-powered AI will map out a professional 4-bar drum pattern for you.
              </p>

              <div className="relative">
                <textarea
                  value={aiPrompt}
