import { Track } from '../types';
import { INSTRUMENT_MIDI_MAP, TOTAL_STEPS } from '../constants';

/**
 * Encodes a number into a MIDI variable-length quantity.
 */
function encodeVariableLength(value: number): number[] {
  const bytes: number[] = [];
  bytes.push(value & 0x7F);
  while (value > 0x7F) {
    value >>= 7;
    bytes.push((value & 0x7F) | 0x80);
  }
  return bytes.reverse();
}

/**
 * Encodes a 32-bit integer into a 4-byte array.
 */
function encodeInt32(value: number): number[] {
  return [
    (value >> 24) & 0xFF,
    (value >> 16) & 0xFF,
    (value >> 8) & 0xFF,
    value & 0xFF
  ];
}

interface MidiEvent {
  tick: number;
  status: number;
  data1: number;
  data2: number;
}

/**
 * Creates a Standard MIDI File (SMF) Type 0 from the sequencer grid.
 */
export const exportToMIDI = (tracks: Track[], bpm: number) => {
  const TICKS_PER_QUARTER = 128;
  const TICKS_PER_STEP = 32; // (128 ticks / 4 steps per quarter)
  const DRUM_CHANNEL = 0x09; // MIDI Channel 10 is 0x09 (0-indexed)

  const midiEvents: MidiEvent[] = [];

  // 1. Collect all NoteOn and NoteOff events
  for (let step = 0; step < TOTAL_STEPS; step++) {
    const startTick = step * TICKS_PER_STEP;
    const endTick = startTick + 10; // Short duration for drum hits

    tracks.forEach(track => {
      if (track.steps[step]) {
        const midiNote = INSTRUMENT_MIDI_MAP[track.id];

        // Note On
        midiEvents.push({
          tick: startTick,
          status: 0x90 | DRUM_CHANNEL,
          data1: midiNote,
          data2: 100 // Velocity
        });

        // Note Off
        midiEvents.push({
          tick: endTick,
          status: 0x80 | DRUM_CHANNEL,
          data1: midiNote,
          data2: 0
        });
      }
    });
  }

  // 2. Sort events by tick time
  midiEvents.sort((a, b) => a.tick - b.tick);

  // 3. Build the Track Data
  const trackBytes: number[] = [];

  // Set Tempo Meta Event
  // Microseconds per quarter note = 60,000,000 / BPM
  const tempo = Math.round(60000000 / bpm);
  trackBytes.push(0x00, 0xFF, 0x51, 0x03, (tempo >> 16) & 0xFF, (tempo >> 8) & 0xFF, tempo & 0xFF);

  let lastTick = 0;
  midiEvents.forEach(event => {
    const deltaTime = event.tick - lastTick;
    trackBytes.push(...encodeVariableLength(deltaTime));
    trackBytes.push(event.status, event.data1, event.data2);
    lastTick = event.tick;
  });

  // End of Track Meta Event
  trackBytes.push(0x00, 0xFF, 0x2F, 0x00);

  // 4. Create chunks
  const headerChunk = [
    0x4D, 0x54, 0x68, 0x64, // MThd
    0x00, 0x00, 0x00, 0x06, // Chunk size
    0x00, 0x00,             // Format 0
    0x00, 0x01,             // 1 track
    (TICKS_PER_QUARTER >> 8) & 0xFF, TICKS_PER_QUARTER & 0xFF // Resolution
  ];

  const trackChunkHeader = [
    0x4D, 0x54, 0x72, 0x6B, // MTrk
    ...encodeInt32(trackBytes.length)
  ];

  // 5. Final File
  const fileData = new Uint8Array([...headerChunk, ...trackChunkHeader, ...trackBytes]);
  const blob = new Blob([fileData], { type: 'audio/midi' });
  const url = URL.createObjectURL(blob);

  const link = document.createElement('a');
  link.href = url;
  link.download = `midnight_beat_${bpm}bpm.mid`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

